unit lipdecide;

interface

uses globals, math;

function REALCOMPARE(A, B: real): COMPTYPE;
procedure DECIDE;

implementation

function REALCOMPARE(A, B: real): COMPTYPE;
const
  EPS = 0.0000005;
begin
  if abs(A - B) < EPS then
    REALCOMPARE := EQ
  else if A < B then
    REALCOMPARE := LT
  else
    REALCOMPARE := GT;
end;

function Dist(i, j: integer): real;
begin
  Dist := sqrt(sqr(X[i] - X[j]) + sqr(Y[i] - Y[j]));
end;

function Area(i, j, k: integer): real;
begin
  Area := 0.5 * abs(X[i]*(Y[j] - Y[k]) + X[j]*(Y[k] - Y[i]) + X[k]*(Y[i] - Y[j]));
end;

function GetQuad(i: integer): integer;
begin
  if (X[i] >= 0) and (Y[i] >= 0) then GetQuad := 1
  else if (X[i] < 0) and (Y[i] >= 0) then GetQuad := 2
  else if (X[i] <= 0) and (Y[i] < 0) then GetQuad := 3
  else GetQuad := 4;
end;

function CanContain(i, j, k: integer; radius: real): boolean;
var
  a, b, c, R: real;
begin
  a := Dist(i, j); b := Dist(j, k); c := Dist(k, i);
  if (a > 2*radius + 1e-9) or (b > 2*radius + 1e-9) or (c > 2*radius + 1e-9) then
    CanContain := false
  else if (a < 1e-9) and (b < 1e-9) and (c < 1e-9) then
    CanContain := true
  else
  begin
    if (a*a + b*b < c*c - 1e-9) or (b*b + c*c < a*a - 1e-9) or (c*c + a*a < b*b - 1e-9) then
      CanContain := true
    else
    begin
      R := (a * b * c) / (4 * Area(i, j, k) + 1e-9);
      CanContain := REALCOMPARE(R, radius) <> GT;
    end;
  end;
end;

procedure DECIDE;
var
  i, j, k, q, p1, p2, p3, start, last: integer;
  tempCMV: VECTOR;
  quads: set of 1..4;
  cos_angle, angle: real;
begin
  for i := 1 to 15 do tempCMV[i] := false;

  for i := 1 to NUMPOINTS - 1 do
    if REALCOMPARE(Dist(i, i + 1), PARAMETERS.LENGTH1) = GT then tempCMV[1] := true;

  for i := 1 to NUMPOINTS - 2 do
    if not CanContain(i, i+1, i+2, PARAMETERS.RADIUS1) then tempCMV[2] := true;

  for i := 1 to NUMPOINTS - 2 do
  begin
    p1 := i; p2 := i+1; p3 := i+2;
    if (Dist(p1, p2) > 1e-9) and (Dist(p2, p3) > 1e-9) then
    begin
      cos_angle := ((X[p1]-X[p2])*(X[p3]-X[p2]) + (Y[p1]-Y[p2])*(Y[p3]-Y[p2])) / (Dist(p1, p2)*Dist(p2, p3));
      if cos_angle < -1.0 then cos_angle := -1.0 else if cos_angle > 1.0 then cos_angle := 1.0;
      angle := arccos(cos_angle);
      if (REALCOMPARE(angle, PI - PARAMETERS.EPSILON) = LT) or (REALCOMPARE(angle, PI + PARAMETERS.EPSILON) = GT) then
        tempCMV[3] := true;
    end;
  end;

  for i := 1 to NUMPOINTS - 2 do
    if REALCOMPARE(Area(i, i+1, i+2), PARAMETERS.AREA1) = GT then tempCMV[4] := true;

  for i := 1 to NUMPOINTS - PARAMETERS.Q_PTS + 1 do
  begin
    quads := [];
    for j := i to i + PARAMETERS.Q_PTS - 1 do quads := quads + [GetQuad(j)];
    if card(quads) > PARAMETERS.QUADS then tempCMV[5] := true;
  end;

  for i := 1 to NUMPOINTS - 1 do
    if REALCOMPARE(X[i+1] - X[i], 0) = LT then tempCMV[6] := true;

  for i := 1 to NUMPOINTS - PARAMETERS.N_PTS + 1 do
  begin
    start := i; last := i + PARAMETERS.N_PTS - 1;
    if Dist(start, last) < 1e-9 then
    begin
      for j := start + 1 to last - 1 do
        if REALCOMPARE(Dist(start, j), PARAMETERS.DIST) = GT then tempCMV[7] := true;
    end
    else
    begin
      for j := start + 1 to last - 1 do
        if REALCOMPARE(2 * Area(start, last, j) / Dist(start, last), PARAMETERS.DIST) = GT then tempCMV[7] := true;
    end;
  end;

  for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
    if REALCOMPARE(Dist(i, i + PARAMETERS.K_PTS + 1), PARAMETERS.LENGTH1) = GT then tempCMV[8] := true;

  for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
    if not CanContain(i, i + PARAMETERS.A_PTS + 1, i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2, PARAMETERS.RADIUS1) then tempCMV[9] := true;

  for i := 1 to NUMPOINTS - PARAMETERS.C_PTS - PARAMETERS.D_PTS - 2 do
  begin
    p1 := i; p2 := i + PARAMETERS.C_PTS + 1; p3 := p2 + PARAMETERS.D_PTS + 1;
    if (Dist(p1, p2) > 1e-9) and (Dist(p2, p3) > 1e-9) then
    begin
      cos_angle := ((X[p1]-X[p2])*(X[p3]-X[p2]) + (Y[p1]-Y[p2])*(Y[p3]-Y[p2])) / (Dist(p1, p2)*Dist(p2, p3));
      if cos_angle < -1.0 then cos_angle := -1.0 else if cos_angle > 1.0 then cos_angle := 1.0;
      angle := arccos(cos_angle);
      if (REALCOMPARE(angle, PI - PARAMETERS.EPSILON) = LT) or (REALCOMPARE(angle, PI + PARAMETERS.EPSILON) = GT) then
        tempCMV[10] := true;
    end;
  end;

  for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
    if REALCOMPARE(Area(i, i + PARAMETERS.E_PTS + 1, i + PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2), PARAMETERS.AREA1) = GT then tempCMV[11] := true;

  for i := 1 to NUMPOINTS - PARAMETERS.G_PTS - 1 do
    if REALCOMPARE(X[i + PARAMETERS.G_PTS + 1] - X[i], 0) = LT then tempCMV[12] := true;

  for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
    if (REALCOMPARE(Dist(i, i + PARAMETERS.K_PTS + 1), PARAMETERS.LENGTH1) = GT) and
       (REALCOMPARE(Dist(i, i + PARAMETERS.K_PTS + 1), PARAMETERS.LENGTH2) = LT) then
       tempCMV[13] := true;

  for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
  begin
    j := i + PARAMETERS.A_PTS + 1; k := j + PARAMETERS.B_PTS + 1;
    if (not CanContain(i, j, k, PARAMETERS.RADIUS1)) and (CanContain(i, j, k, PARAMETERS.RADIUS2)) then
       tempCMV[14] := true;
  end;

  for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
  begin
    j := i + PARAMETERS.E_PTS + 1; k := j + PARAMETERS.F_PTS + 1;
    if (REALCOMPARE(Area(i, j, k), PARAMETERS.AREA1) = GT) and (REALCOMPARE(Area(i, j, k), PARAMETERS.AREA2) = LT) then
       tempCMV[15] := true;
  end;

  for i := 1 to 15 do
  begin
    PUM[i, i] := tempCMV[i];
    for j := 1 to 15 do
      if i <> j then
        case LCM[i, j] of
          NOTUSED: PUM[i, j] := true;
          ORR:     PUM[i, j] := tempCMV[i] or tempCMV[j];
          ANDD:    PUM[i, j] := tempCMV[i] and tempCMV[j];
        end;
  end;

  for i := 1 to 15 do
  begin
    FUV[i] := true;
    for j := 1 to 15 do
      if not PUM[i, j] then
      begin
        FUV[i] := false;
        break;
      end;
  end;

  LAUNCH := true;
  for i := 1 to 15 do
    if not FUV[i] then
    begin
      LAUNCH := false;
      break;
    end;
end;

end.
